import type { HTMLAttributes, Ref } from "react"
import { cn } from "@/lib/utils"
import type { FigletFont } from "./get-figlet-text"

export interface LogoProps extends HTMLAttributes<HTMLPreElement> {
  text: string
  font?: FigletFont
  asciiText?: string
  ref?: Ref<HTMLPreElement>
}

export function Logo({
  ref,
  text,
  font: _font,
  asciiText,
  className,
  ...props
}: LogoProps) {
  return (
    <pre
      ref={ref}
      {...(asciiText ? { role: "img", "aria-label": text } : undefined)}
      className={cn(
        asciiText
          ? "font-mono whitespace-pre leading-none select-none"
          : "text-lg font-bold tracking-widest",
        className,
      )}
      {...props}
    >
      {asciiText ?? text}
    </pre>
  )
}

import figlet from "figlet"
import bigFont from "figlet/importable-fonts/Big.js"
import smallFont from "figlet/importable-fonts/Small.js"

/** Supported figlet font names. @see diffgazer/packages/core/src/get-figlet.ts for the canonical copy. */
export type FigletFont = "Big" | "Small"

const loadedFonts = new Set<FigletFont>()

function ensureFont(font: FigletFont): void {
  if (loadedFonts.has(font)) return
  figlet.parseFont(font, font === "Big" ? bigFont : smallFont)
  loadedFonts.add(font)
}

export function getFigletText(
  text: string,
  font: FigletFont = "Big",
): string | null {
  try {
    ensureFont(font)
    return figlet.textSync(text, { font })
  } catch {
    return null
  }
}
